- (UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    static NSString *cellIdentifier = @"HomeCell";
    HomeCollectionViewCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:cellIdentifier forIndexPath:indexPath];

    // 设置按钮点击回调
    __weak typeof(self) weakSelf = self;
    cell.actionButtonClickBlock = ^(BOOL isUnlocked, NSInteger requiredCoins) {
        __strong typeof(weakSelf) strongSelf = weakSelf;
        [strongSelf handleActionButtonClickAtIndexPath:indexPath isUnlocked:isUnlocked requiredCoins:requiredCoins];
    };

    NSMutableDictionary *item = self.items[indexPath.row];
    BOOL isUnlocked = [item[@"unlocked"] boolValue];
    NSInteger requiredCoins = [item[@"requiredCoins"] integerValue];
    NSString *lockedName = item[@"image_locked"];
    NSString *unlockedName = item[@"image_unlocked"];
    NSString *imageName = isUnlocked ? (unlockedName.length > 0 ? unlockedName : [self unlockedImageNameFromLocked:lockedName]) : lockedName;
    NSString *title = item[@"title"];
    NSString *desc = item[@"desc"];
    NSString *unlockText = isUnlocked ? nil : [NSString stringWithFormat:@"解锁(需%ld专注币)", (long)requiredCoins];

    if (unlockText) {
        [cell configureWithImage:imageName title:title description:desc isUnlocked:isUnlocked unlockText:unlockText];
    } else {
        [cell configureWithImage:imageName title:title description:desc isUnlocked:isUnlocked];
    }

    return cell;
}

