// 按钮处理方法（保持不变）
- (void)handleActionButtonClickAtIndexPath:(NSIndexPath *)indexPath isUnlocked:(BOOL)isUnlocked requiredCoins:(NSInteger)requiredCoins {
    if (isUnlocked) {
        [self enterImmersiveExperienceAtIndexPath:indexPath];
    } else {
        if ([[FocusManager sharedManager] hasEnoughCoins:requiredCoins]) {
            [self unlockContentAtIndexPath:indexPath requiredCoins:requiredCoins];
        } else {
            [self showInsufficientCoinsAlert];
        }
    }
}

- (void)unlockContentAtIndexPath:(NSIndexPath *)indexPath requiredCoins:(NSInteger)requiredCoins {
    [[FocusManager sharedManager] deductCoins:requiredCoins];
    [self showUnlockSuccessAlert];

    NSMutableDictionary *item = self.items[indexPath.row];
    item[@"unlocked"] = @(YES);
    [self.collectionView reloadItemsAtIndexPaths:@[indexPath]];
}

- (void)enterImmersiveExperienceAtIndexPath:(NSIndexPath *)indexPath {
    NSMutableDictionary *item = self.items[indexPath.row];
    SoundViewController *vc = [[SoundViewController alloc] init];
    UINavigationController *navController = [[UINavigationController alloc] initWithRootViewController:vc];
    navController.modalPresentationStyle = UIModalPresentationOverFullScreen;
    vc.titleText = item[@"title"];
    vc.mainImageName = item[@"image_unlocked"] ?: [self unlockedImageNameFromLocked:item[@"image_locked"]];
    vc.subtitleText = item[@"subtitle"] ?: @"";
    vc.descriptionText = item[@"desc"] ?: @"";
    vc.backgroundImageName = item[@"backgroundImage"] ?: @"";
    [self presentViewController:navController animated:YES completion:nil];
}

- (void)showInsufficientCoinsAlert {
    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"专注币不足"
                                                                   message:@"您的专注币不足。请完成任务获取更多专注币。"
                                                            preferredStyle:UIAlertControllerStyleAlert];
    UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil];
    [alert addAction:okAction];
    [self presentViewController:alert animated:YES completion:nil];
}

- (void)showUnlockSuccessAlert {
    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"解锁成功"
                                                                   message:@"内容已成功解锁。现在可以开始沉浸式体验了。"
                                                            preferredStyle:UIAlertControllerStyleAlert];
    UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil];
    [alert addAction:okAction];
    [self presentViewController:alert animated:YES completion:nil];
}

