static NSString * const FocusCoinsUserDefaultsKey = @"FocusCoins";

NSString * const FocusManagerDidUpdateCoinsNotification = @"FocusManagerDidUpdateCoinsNotification";

@implementation FocusManager

+ (instancetype)sharedManager {
    static FocusManager *sharedInstance = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        sharedInstance = [[self alloc] init];
        NSInteger saved = [[NSUserDefaults standardUserDefaults] integerForKey:FocusCoinsUserDefaultsKey];
        if (saved < 0) saved = 0;
        if (saved > 70) saved = 70;
        sharedInstance.focusCoins = saved;
    });
    return sharedInstance;
}

- (BOOL)hasEnoughCoins:(NSInteger)requiredCoins {
    return self.focusCoins >= requiredCoins;
}

- (void)deductCoins:(NSInteger)coins {
    if (coins <= 0) return;
    if (self.focusCoins < coins) return;
    self.focusCoins -= coins;
    [[NSUserDefaults standardUserDefaults] setInteger:self.focusCoins forKey:FocusCoinsUserDefaultsKey];
    [[NSUserDefaults standardUserDefaults] synchronize];
    [[NSNotificationCenter defaultCenter] postNotificationName:FocusManagerDidUpdateCoinsNotification object:self];
}

- (void)addCoins:(NSInteger)coins {
    if (coins <= 0) return;
    NSInteger newValue = self.focusCoins + coins;
    if (newValue > 70) newValue = 70;
    self.focusCoins = newValue;
    [[NSUserDefaults standardUserDefaults] setInteger:self.focusCoins forKey:FocusCoinsUserDefaultsKey];
    [[NSUserDefaults standardUserDefaults] synchronize];
    [[NSNotificationCenter defaultCenter] postNotificationName:FocusManagerDidUpdateCoinsNotification object:self];
}

@end

