    float systemVolume = [[[notification userInfo] objectForKey:@"AVSystemController_AudioVolumeNotificationParameter"] floatValue];
    self.volumeSlider.value = systemVolume;
}

- (void)playOrPauseButtonClicked {
    if (self.isPlaying) {
        // 暂停播放
        [self.audioPlayer pause];
        self.isPlaying = NO;
        [_playOrPauseButton setBackgroundImage:[UIImage imageNamed:@"A_play"] forState:UIControlStateNormal];
    } else {
        // 播放音频
        NSString *audioName = @"";
        if ([self.title isEqual:@"小雨淅淅"]) {
            audioName = @"Light rain";
        } else if([self.title isEqual:@"篝火"]){
            audioName = @"Bonfire";
        } else if([self.title isEqual:@"海浪"]){
            audioName = @"Waves";
        } else if([self.title isEqual:@"指尖键盘"]){
            audioName = @"keyboard tapping";
        }
        [self playAudioWithFilename:audioName];
    }
}

- (void)playAudioWithFilename:(NSString *)filename {
    if (!filename || filename.length == 0) {
        NSLog(@"No filename provided for audio playback");
        return;
    }

    // 查找音频文件
    NSString *cleanFilename = [filename stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSURL *audioURL = [[NSBundle mainBundle] URLForResource:cleanFilename withExtension:@"mp3"];

    if (!audioURL) {
        [SVProgressHUD showErrorWithStatus:@"Audio file not found"];
        return;
    }

    AVAudioSession *session = [AVAudioSession sharedInstance];
    NSError *sessionError = nil;
    [session setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:&sessionError];
    if (sessionError) {
        [SVProgressHUD showErrorWithStatus:@"Audio session configuration failed"];
        return;
    }
    [session setActive:YES error:&sessionError];
    if (sessionError) {
        [SVProgressHUD showErrorWithStatus:@"Audio session activation failed"];
        return;
    }

    NSError *error = nil;
    self.audioPlayer = [[AVAudioPlayer alloc] initWithContentsOfURL:audioURL error:&error];
    if (error) {
        NSLog(@"Error initializing audio player: %@", error.localizedDescription);
        [SVProgressHUD showErrorWithStatus:@"Failed to initialize audio player"];
        return;
    }

    self.audioPlayer.delegate = self;
    self.audioPlayer.volume = self.volumeSlider.value;
    self.audioPlayer.numberOfLoops = -1;
    [self.audioPlayer prepareToPlay];
    [self.audioPlayer play];

    self.isPlaying = YES;
    [_playOrPauseButton setBackgroundImage:[UIImage imageNamed:@"A_pause"] forState:UIControlStateNormal];
}

- (void)audioPlayerDidFinishPlaying:(AVAudioPlayer *)player successfully:(BOOL)flag {
    self.isPlaying = NO;
    [_playOrPauseButton setBackgroundImage:[UIImage imageNamed:@"A_play"] forState:UIControlStateNormal];
}

- (void)returnButtonClicked {
    if (self.isPlaying && self.audioPlayer) {
        [self.audioPlayer stop];
        self.isPlaying = NO;
    }

