+#pragma mark - audio
+
+- (void)playAudioForItem:(NSDictionary *)item {
+    NSString *audioName = item[@"audio"];
+    if (audioName.length == 0) return;
+    NSURL *audioURL = [[NSBundle mainBundle] URLForResource:audioName withExtension:@"mp3"];
+    if (!audioURL) {
+        [SVProgressHUD showErrorWithStatus:@"音频文件不存在"];
+        return;
+    }
+    
+    AVAudioSession *session = [AVAudioSession sharedInstance];
+    NSError *sessionError = nil;
+    [session setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:&sessionError];
+    [session setActive:YES error:&sessionError];
+    if (sessionError) {
+        [SVProgressHUD showErrorWithStatus:@"音频播放失败"];
+        return;
+    }
+    
+    NSError *error = nil;
+    self.audioPlayer = [[AVAudioPlayer alloc] initWithContentsOfURL:audioURL error:&error];
+    if (error) {
+        [SVProgressHUD showErrorWithStatus:@"音频播放失败"];
+        return;
+    }
+    self.audioPlayer.delegate = self;
+    self.audioPlayer.numberOfLoops = -1;
+    [self.audioPlayer prepareToPlay];
+    [self.audioPlayer play];
+    self.isPlaying = YES;
+    [self updatePlayButton];
+}
+
+- (void)stopAudio {
+    [self.audioPlayer stop];
+    self.audioPlayer = nil;
+    self.isPlaying = NO;
+    [self updatePlayButton];
+}
+
+- (void)updatePlayButton {
+    NSString *imageName = self.isPlaying ? @"A_pause" : @"A_play";
+    [self.playButton setImage:[UIImage imageNamed:imageName] forState:UIControlStateNormal];
+}
+
+- (void)audioPlayerDidFinishPlaying:(AVAudioPlayer *)player successfully:(BOOL)flag {
+    [self stopAudio];
+}
