#import "FocusViewController.h"
#import <AVFoundation/AVFoundation.h>

#if ENABLE_ADS
#import <BUAdSDK/BUAdSDK.h>
#import "AdManager.h"

@interface HomeViewController () <AVAudioPlayerDelegate, BUNativeExpressBannerViewDelegate>

@property(strong, nonatomic) BUNativeExpressBannerView *bannerAdView;
@property(assign, nonatomic) CGFloat bannerAdHeight;

#else

@interface HomeViewController () <AVAudioPlayerDelegate>

#endif

@property (nonatomic, strong) NSArray<NSDictionary *> *items;
@property (nonatomic, assign) NSInteger currentIndex;
@property (nonatomic, strong) UIImageView *cardView;
@property (nonatomic, strong) UIImageView *mainImageView;
@property (nonatomic, strong) UIImageView *lockImageView;
@property (nonatomic, strong) UILabel *titleLabel;
@property (nonatomic, strong) UILabel *descriptionLabel;
@property (nonatomic, strong) UIButton *previousButton;
@property (nonatomic, strong) UIButton *playButton;
@property (nonatomic, strong) UIButton *nextButton;
@property (nonatomic, strong) UIView *unlockContainerView;
@property (nonatomic, strong) UILabel *unlockHintLabel;
@property (nonatomic, strong) UIButton *unlockButton;
@property (nonatomic, strong) AVAudioPlayer *audioPlayer;
@property (nonatomic, assign) BOOL isPlaying;

@end

@implementation HomeViewController

- (instancetype)init {
    self = [super init];
    if (self) {
#if ENABLE_ADS
        self.bannerAdHeight = ZOOM(75);
#endif
        self.currentIndex = 0;
    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];
    UIImage *image = [[UIImage imageNamed:@"A_gotoFocus"] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
    UIBarButtonItem *goButton = [[UIBarButtonItem alloc] initWithImage:image
                                                                 style:UIBarButtonItemStylePlain
                                                                target:self
                                                                action:@selector(gotoFocus)];
    self.navigationItem.leftBarButtonItem = goButton;
    [self setupItems];
    [self setupUI];
    [self refreshContent];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(focusCoinsDidUpdate) name:FocusManagerDidUpdateCoinsNotification object:nil];
}

- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
#if ENABLE_ADS
    [self groMoreBannerAdLoad];
#endif
}

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
    [self stopAudio];
}

#pragma mark - setup

- (void)setupItems {
    self.items = @[
        @{
            @"id": @"rain",
            @"title": @"小雨淅淅",
            @"desc": @"轻柔的雨滴声带来平静与放松",
            @"image_unlocked": @"A_rain_image",
            @"image_locked": @"A_rain_image",
            @"audio": @"Light rain",
            @"requiredCoins": @(0)
        },
        @{
            @"id": @"fire",
            @"title": @"篝火",
            @"desc": @"温暖而平静的篝火噼啪声",
            @"image_unlocked": @"A_fire_image",
            @"image_locked": @"A_fire_image_locked",
            @"audio": @"Bonfire",
            @"requiredCoins": @(10)
        },
        @{
            @"id": @"wave",
            @"title": @"海浪",
            @"desc": @"舒缓的海浪声，平静的海岸",
            @"image_unlocked": @"A_wave_image",
            @"image_locked": @"A_wave_image_locked",
            @"audio": @"Waves",
            @"requiredCoins": @(15)
        }
    ];
}

- (void)setupUI {
    self.view.backgroundColor = RGB(235, 235, 235);

    UILabel *hintLabel = [[UILabel alloc] init];
    hintLabel.text = @"选择你的宁静时刻";
    hintLabel.textColor = RGB(102, 102, 102);
    hintLabel.font = [UIFont systemFontOfSize:ZOOM(14) weight:UIFontWeightRegular];

    [self.view addSubview:hintLabel];
    [self.view addSubview:self.cardView];
    [self.cardView addSubview:self.mainImageView];
    [self.cardView addSubview:self.lockImageView];
    [self.cardView addSubview:self.titleLabel];
    [self.cardView addSubview:self.descriptionLabel];
    [self.view addSubview:self.previousButton];
    [self.view addSubview:self.playButton];
    [self.view addSubview:self.nextButton];
    [self.view addSubview:self.unlockContainerView];
    [self.unlockContainerView addSubview:self.unlockHintLabel];
    [self.unlockContainerView addSubview:self.unlockButton];

