        make.left.equalTo(self.view).offset(ZOOM(16));
        make.top.equalTo(self.view.mas_safeAreaLayoutGuideTop).offset(ZOOM(12));
    }];

    [self.cardView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(hintLabel.mas_bottom).offset(ZOOM(10));
        make.left.equalTo(self.view).offset(ZOOM(12));
        make.right.equalTo(self.view).offset(ZOOM(-12));
        make.height.mas_equalTo(ZOOM(292));
