        make.right.equalTo(self.cardView).offset(ZOOM(-10));
        make.height.mas_equalTo(ZOOM(190));
    }];

    [self.lockImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.center.equalTo(self.mainImageView);
        make.width.height.mas_equalTo(ZOOM(54));
    }];

    [self.titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.mainImageView.mas_bottom).offset(ZOOM(12));
        make.centerX.equalTo(self.cardView);
        make.left.greaterThanOrEqualTo(self.cardView).offset(ZOOM(16));
