            [self.focusTime setControlsEnabled:YES];
            [self.restTime setControlsEnabled:YES];

            // 重置倒计时标签为当前专注时间
            [self updateCountdownLabelWithSeconds:self.focusMinutes * 60];

            if (self.focusMinutes >= 25) {
                if ([FocusManager sharedManager].focusCoins < 70) {
                    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"恭喜完成🎉" message:@"恭喜完成1次专注，专注币+5！" preferredStyle:UIAlertControllerStyleAlert];
                    UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil];
                    [alert addAction:okAction];
                    [self presentViewController:alert animated:YES completion:nil];

                    [[FocusManager sharedManager] addCoins:MIN(5, 70 - [FocusManager sharedManager].focusCoins)];
                } else {
                    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"专注币已满" message:@"您已达到70个专注币上限，专注币可用于解锁首页音频，快去使用吧！" preferredStyle:UIAlertControllerStyleAlert];
