    [super viewDidLayoutSubviews];
    if (self.resultGradientLayer) {
        self.resultGradientLayer.frame = self.resultView.bounds;
    }
}

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
    [self.timer invalidate];
    self.timer = nil;
}

- (void)startFocus {
    if (self.isRunning) return;
    self.isRunning = YES;
    self.statusLabel.text = @"专注中";
    [self.actionButton setTitle:@"专注中" forState:UIControlStateNormal];
    [self.focusTime setControlsEnabled:NO];
    [self.restTime setControlsEnabled:NO];
    [self startTimerWithSeconds:self.focusMinutes * 60 phase:FocusPhaseFocusing];
}

- (void)startTimerWithSeconds:(NSInteger)seconds phase:(FocusPhase)phase {
    self.phase = phase;
    self.remainingSeconds = seconds;
    [self.timer invalidate];
    self.timer = [NSTimer scheduledTimerWithTimeInterval:1.0 target:self selector:@selector(timerTick) userInfo:nil repeats:YES];
    [[NSRunLoop mainRunLoop] addTimer:self.timer forMode:NSRunLoopCommonModes];
    [self updateCountdownLabelWithSeconds:self.remainingSeconds];
}

- (void)timerTick {
    if (self.remainingSeconds <= 0) {
        [self.timer invalidate];
        self.timer = nil;
        if (self.phase == FocusPhaseFocusing) {
            self.statusLabel.text = @"休息中";
            [self.actionButton setTitle:@"休息中" forState:UIControlStateNormal];
            [self startTimerWithSeconds:self.restMinutes * 60 phase:FocusPhaseResting];
        } else if (self.phase == FocusPhaseResting) {
            self.statusLabel.text = @"准备开始";
            self.isRunning = NO;
            [self.actionButton setTitle:@"开始" forState:UIControlStateNormal];
            [self.focusTime setControlsEnabled:YES];
            [self.restTime setControlsEnabled:YES];

            // 重置倒计时标签为当前专注时间
            [self updateCountdownLabelWithSeconds:self.focusMinutes * 60];

            if (self.focusMinutes >= 25) {
                if ([FocusManager sharedManager].focusCoins < 70) {
                    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"恭喜完成🎉" message:@"恭喜完成1次专注，专注币+5！" preferredStyle:UIAlertControllerStyleAlert];
                    UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil];
                    [alert addAction:okAction];
                    [self presentViewController:alert animated:YES completion:nil];

                    [[FocusManager sharedManager] addCoins:MIN(5, 70 - [FocusManager sharedManager].focusCoins)];
                } else {
                    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"专注币已满" message:@"您已达到70个专注币上限，专注币可用于解锁首页音频，快去使用吧！" preferredStyle:UIAlertControllerStyleAlert];
                    UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"知道了" style:UIAlertActionStyleDefault handler:nil];
                    [alert addAction:okAction];
                    [self presentViewController:alert animated:YES completion:nil];
                }
            } else {
                UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"专注完成✅" message:[NSString stringWithFormat:@"您已完成%ld分钟专注！专注时间需大于等于25分钟才能获得专注币，下次试试更长时间吧~", (long)self.focusMinutes] preferredStyle:UIAlertControllerStyleAlert];
                UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil];
                [alert addAction:okAction];
                [self presentViewController:alert animated:YES completion:nil];
            }
            [self updateCoinsUI];
        }
        return;
    }
    self.remainingSeconds -= 1;
    [self updateCountdownLabelWithSeconds:self.remainingSeconds];
}

- (void)updateCountdownLabelWithSeconds:(NSInteger)seconds {
    NSInteger m = seconds / 60;
    NSInteger s = seconds % 60;
    self.countDownLabel.text = [NSString stringWithFormat:@"%02ld:%02ld", (long)m, (long)s];
}

- (void)updateCoinsUI {
    NSInteger coins = [FocusManager sharedManager].focusCoins;
    self.processProgress.progress = coins / 70.0f;
    self.processLabel.text = [NSString stringWithFormat:@"已获得 %ld/70 专注币", (long)coins];
}

- (UILabel *)tipLabel {
    if (!_tipLabel) {
        _tipLabel = [[UILabel alloc] init];

        NSMutableAttributedString *attributedText = [[NSMutableAttributedString alloc] initWithString:@"温馨提示：\n1. 每次专注成功 +5专注币\n2. 每次专注时长需大于等于25分钟才算成功\n3. 专注币仅用于解锁首页音频"];

        [attributedText addAttribute:NSFontAttributeName value:[UIFont systemFontOfSize:ZOOM(14)] range:NSMakeRange(0, attributedText.length)];
        [attributedText addAttribute:NSForegroundColorAttributeName value:(id)RGB(153, 153, 153).CGColor range:NSMakeRange(0, attributedText.length)];

        NSRange range1 = [attributedText.string rangeOfString:@"+5专注币"];
        if (range1.location != NSNotFound) {
            [attributedText addAttribute:NSForegroundColorAttributeName value:(id)RGB(102, 102, 102).CGColor range:range1];
        }

        NSRange range2 = [attributedText.string rangeOfString:@"大于等于25分钟"];
        if (range2.location != NSNotFound) {
            [attributedText addAttribute:NSForegroundColorAttributeName value:(id)RGB(102, 102, 102).CGColor range:range2];
        }

        _tipLabel.attributedText = attributedText;
        _tipLabel.numberOfLines = 0;
    }
    return _tipLabel;
}

- (UIImageView *)coinImageView {
    if (!_coinImageView) {
        _coinImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:@"A_focusCoin"]];
    }
    return _coinImageView;
}

- (UILabel *)coinNameLabel {
    if (!_coinNameLabel) {
        _coinNameLabel = [[UILabel alloc] init];
        _coinNameLabel.text = @"专注币";
        _coinNameLabel.textColor = RGB(51, 51, 51);
        _coinNameLabel.font = [UIFont boldSystemFontOfSize:ZOOM(18)];
    }
    return _coinNameLabel;
}

- (UIProgressView *)processProgress {
    if (!_processProgress) {
        _processProgress = [[UIProgressView alloc] initWithProgressViewStyle:UIProgressViewStyleDefault];
        _processProgress.progressTintColor = RGBA(217, 159, 50, 1);
        _processProgress.trackTintColor = RGB(255, 255, 255);
        _processProgress.progress = [FocusManager sharedManager].focusCoins / 70.0f;
        _processProgress.layer.cornerRadius = ZOOM(5);
        _processProgress.layer.masksToBounds = YES;
        _processProgress.clipsToBounds = YES;
    }
    return _processProgress;
}

