- (void)gotoFocus {
    FocusViewController *fVC = [[FocusViewController alloc] init];
    UINavigationController *nav = [[UINavigationController alloc] initWithRootViewController:fVC];
    nav.modalPresentationStyle = UIModalPresentationFullScreen;
    [self presentViewController:nav animated:YES completion:nil];
}

- (void)showPreviousItem {
    if (self.items.count == 0) return;
    [self stopAudio];
    self.currentIndex = (self.currentIndex - 1 + self.items.count) % self.items.count;
    [self refreshContent];
}

- (void)showNextItem {
    if (self.items.count == 0) return;
    [self stopAudio];
    self.currentIndex = (self.currentIndex + 1) % self.items.count;
    [self refreshContent];
}

- (void)playButtonTapped {
    NSDictionary *item = [self currentItem];
    if (![self isCurrentItemUnlocked]) {
        [self tryUnlockCurrentItem];
        return;
    }
    if (self.isPlaying) {
        [self stopAudio];
        return;
    }
    [self playAudioForItem:item];
}

- (void)unlockButtonTapped {
    [self tryUnlockCurrentItem];
}

- (void)focusCoinsDidUpdate {
    [self refreshContent];
}

#pragma mark - content

- (NSDictionary *)currentItem {
    if (self.items.count == 0) return @{};
    return self.items[self.currentIndex];
}

- (BOOL)isCurrentItemUnlocked {
    NSDictionary *item = [self currentItem];
    NSInteger requiredCoins = [item[@"requiredCoins"] integerValue];
    if (requiredCoins <= 0) return YES;
    return [[FocusManager sharedManager] isContentUnlocked:item[@"id"]];
}

- (void)refreshContent {
    NSDictionary *item = [self currentItem];
    BOOL isUnlocked = [self isCurrentItemUnlocked];
    NSString *imageName = isUnlocked ? item[@"image_unlocked"] : item[@"image_locked"];
    NSInteger requiredCoins = [item[@"requiredCoins"] integerValue];

    self.mainImageView.image = [UIImage imageNamed:imageName];
    self.titleLabel.text = item[@"title"];
    self.descriptionLabel.text = item[@"desc"];
    self.lockImageView.hidden = isUnlocked;
    self.unlockContainerView.hidden = isUnlocked;
    self.unlockHintLabel.text = [NSString stringWithFormat:@"专注25分钟可解锁，需%ld专注币", (long)requiredCoins];
    [self updatePlayButton];
}

- (void)tryUnlockCurrentItem {
    NSDictionary *item = [self currentItem];
    NSInteger requiredCoins = [item[@"requiredCoins"] integerValue];
    if (requiredCoins <= 0) {
        return;
    }
    if ([[FocusManager sharedManager] hasEnoughCoins:requiredCoins]) {
        [[FocusManager sharedManager] deductCoins:requiredCoins];
        [[FocusManager sharedManager] unlockContent:item[@"id"]];
        [self refreshContent];
        [self showUnlockSuccessAlert];
        return;
    }
    [self showInsufficientCoinsAlert];
}

#pragma mark - audio

- (void)playAudioForItem:(NSDictionary *)item {
    NSString *audioName = item[@"audio"];
    if (audioName.length == 0) return;
    NSURL *audioURL = [[NSBundle mainBundle] URLForResource:audioName withExtension:@"mp3"];
    if (!audioURL) {
        [SVProgressHUD showErrorWithStatus:@"音频文件不存在"];
        return;
    }

    AVAudioSession *session = [AVAudioSession sharedInstance];
    NSError *sessionError = nil;
    [session setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:&sessionError];
    [session setActive:YES error:&sessionError];
    if (sessionError) {
        [SVProgressHUD showErrorWithStatus:@"音频播放失败"];
        return;
    }

    NSError *error = nil;
    self.audioPlayer = [[AVAudioPlayer alloc] initWithContentsOfURL:audioURL error:&error];
    if (error) {
        [SVProgressHUD showErrorWithStatus:@"音频播放失败"];
        return;
    }
    self.audioPlayer.delegate = self;
    self.audioPlayer.numberOfLoops = -1;
    [self.audioPlayer prepareToPlay];
    [self.audioPlayer play];
    self.isPlaying = YES;
    [self updatePlayButton];
}

- (void)stopAudio {
    [self.audioPlayer stop];
    self.audioPlayer = nil;
    self.isPlaying = NO;
    [self updatePlayButton];
}

- (void)updatePlayButton {
    NSString *imageName = self.isPlaying ? @"A_pause" : @"A_play";
    [self.playButton setImage:[UIImage imageNamed:imageName] forState:UIControlStateNormal];
}

- (void)audioPlayerDidFinishPlaying:(AVAudioPlayer *)player successfully:(BOOL)flag {
    [self stopAudio];
}

